// Prepare raw email data for AI extraction (v11.1)
// v11.1: skip-flag pattern replaces `return []` to avoid n8n 2.14 Task Runner
//        "json property isn't an object" errors that were aborting batches and
//        dropping legitimate emails sharing the Outlook polling cycle.
// v11.1: email body preserves line breaks for dashboard display (two versions —
//        bodyForDisplay keeps \n, bodyForAI collapses whitespace for Groq).
// v11: KAN-36 extraction fields (initiator_name, purpose, cost_center)
// v10.1: KAN-35 payment_date + payroll_period
// v10: KAN-30 payment_type classification + attachment fix + verification checklist
// v5.1: full email body passthrough, circuit breaker fix
// v3: binary attachment extraction + rate limiting
// MODE: Run Once for Each Item (n8n 2.x Task Runner compatible)

const item = $input.item;

// v11.1 SKIP PATTERN: always return a valid json object. Skip Filter IF node
// downstream routes _skip:true items to a dead-end. No more `return []` errors.
const skip = (reason) => ({ json: { _skip: true, _skip_reason: reason } });

// Error guard — skip binary-only items and malformed emails
if (!item.json || typeof item.json !== 'object' || Array.isArray(item.json)) {
  return skip('malformed_item');
}
const d = item.json;

// Skip items that are just binary attachments (no email metadata)
if (!d.subject && !d.bodyPreview && !d.snippet && !d.Subject && !d.From && !(d.body && d.body.content) && !(d.payload && d.payload.headers) && !d.from) {
  return skip('no_email_metadata');
}

// Rate limit: text calls (persists across production executions)
const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (staticData.date !== today) {
  staticData.date = today;
  staticData.textCalls = 0;
  staticData.visionCalls = 0;
  staticData.visionErrors = 0;
}
if (staticData.textCalls >= 100) {
  return skip('daily_text_cap_reached');
}
staticData.textCalls++;

// Helper: resolve a value that might be string, object, or array to a readable string
function resolveValue(val) {
  if (typeof val === 'string') return val;
  if (val && typeof val === 'object') {
    if (val.text && typeof val.text === 'string') return val.text;
    if (Array.isArray(val.value) && val.value[0]) {
      const parts = val.value.map(v => v.address ? (v.name ? v.name + ' <' + v.address + '>' : v.address) : '');
      return parts.filter(Boolean).join(', ');
    }
    if (val.address) return val.name ? val.name + ' <' + val.address + '>' : val.address;
    if (Array.isArray(val)) {
      return val.map(v => resolveValue(v)).filter(Boolean).join(', ');
    }
    try { const j = JSON.stringify(val); if (j !== '{}') return j; } catch(e) {}
  }
  return '';
}

// Helper: extract any email header by name (works across all Gmail data formats)
function getHeader(name) {
  if (d.payload && d.payload.headers && Array.isArray(d.payload.headers)) {
    const h = d.payload.headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase());
    if (h && h.value) return h.value;
  }
  const capKey = name.charAt(0).toUpperCase() + name.slice(1);
  if (d[capKey]) return resolveValue(d[capKey]);
  if (d[name.toLowerCase()]) return resolveValue(d[name.toLowerCase()]);
  if (d.headers && typeof d.headers === 'object' && !Array.isArray(d.headers)) {
    const val = d.headers[name] || d.headers[name.toLowerCase()];
    if (val) return resolveValue(val);
  }
  return '';
}

const isEmail = d.snippet !== undefined || d.threadId !== undefined || d.Subject !== undefined || d.From !== undefined || (d.payload && d.payload.headers) || d.bodyPreview !== undefined || (d.from && d.from.emailAddress);
const source = isEmail ? 'email' : 'webhook';

const subject = isEmail
  ? (d.subject || getHeader('Subject') || '')
  : (d.body?.subject || d.subject || '');

// LOOP GUARD: skip our own outbound emails (notifications + returns) that land in emoney@zeyalabs.ai via CC
// v10.1+ fix: sender-based check catches return emails + future outbound types.
// Subject checks kept as belt-and-suspenders defense.
const senderEmailAddr = (d.from && d.from.emailAddress ? d.from.emailAddress.address : '').toLowerCase();
if (isEmail && (senderEmailAddr === 'emoney@zeyalabs.ai' || subject.includes('EMI Pipeline:') || subject.includes('EMI Pipeline \u2014'))) {
  return skip('loop_guard_self_send');
}

// v6: Skip internal Yoma/Wave emails that aren't disbursement requests
const internalDomains = ['yoma.com.mm', 'wavemoney.com.mm'];
const senderDomain = (d.from && d.from.emailAddress ? d.from.emailAddress.address : '').split('@')[1] || '';
if (isEmail && internalDomains.includes(senderDomain) && !subject.toLowerCase().includes('disbursement') && !subject.toLowerCase().includes('payroll') && !subject.toLowerCase().includes('salary')) {
  return skip('internal_domain_non_disbursement');
}

let body = '';
if (isEmail) {
  body = d.textPlain || d.text || (d.body && d.body.content ? d.body.content : '') || d.bodyPreview || d.snippet || d.textHtml || '';
  if ((!body || body.length < 50) && d.payload && d.payload.parts) {
    for (const part of d.payload.parts) {
      if (part.mimeType === 'text/plain' && part.body && part.body.data) {
        try { body = Buffer.from(part.body.data, 'base64').toString('utf-8'); } catch(e) {}
        break;
      }
    }
  }
  if ((!body || body.length < 50) && d.payload && d.payload.body && d.payload.body.data) {
    try { body = Buffer.from(d.payload.body.data, 'base64').toString('utf-8'); } catch(e) {}
  }
  // v11.1 + v11.2 + v11.3 + v11.4 SCOPE FIX: Build TWO body versions
  //   1) bodyForDisplay — preserve line breaks (for dashboard "Show full email")
  //   2) body (collapsed) — fed to Groq prompt (existing behavior)
  //
  // v11.4 SCOPE FIX: declare bodyForDisplay at function scope (var inside if)
  // instead of let (block-scoped). Previously v11.3 heuristic was mutating a
  // block-scoped variable that evaporated at block exit — the return statement
  // read `typeof bodyForDisplay === 'string'` from function scope (undefined)
  // and fell back to the collapsed `body` version. Empirical proof: SQL on
  // TKT-038 showed has_newlines=false despite the heuristic code path running.
  //
  // v11.3 addition: After HTML stripping, if the result STILL has no newlines
  // AND is longer than 200 chars, inject heuristic newlines before common email
  // structure markers (Field:, bullets, signatures). This catches Outlook Web's
  // case of wrapping all content in inline tags only.
  var bodyForDisplay = body
    // Strip HTML conditional comments (<!--[if gte mso 9]>...<![endif]-->)
    .replace(/<!--\[if[\s\S]*?<!\[endif\]-->/g, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    // Strip <head>/<style>/<script> blocks entirely
    .replace(/<(head|style|script)\b[^>]*>[\s\S]*?<\/\1>/gi, ' ')
    // Convert HTML entities representing newlines BEFORE tag stripping
    .replace(/&#13;&#10;/g, '\n')
    .replace(/&#10;/g, '\n')
    .replace(/&#13;/g, '\n')
    .replace(/&#xD;/gi, '\n')
    .replace(/&#xA;/gi, '\n')
    // Convert block-breaking tags to newline (v11.3: added span as Outlook often wraps paragraphs in spans with no block tags)
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/(p|div|li|tr|h[1-6]|blockquote|section|article|address)>/gi, '\n')
    .replace(/<\/(ul|ol|table)>/gi, '\n\n')
    // Microsoft Office placeholder tag — treat as noise
    .replace(/<o:p>\s*<\/o:p>/gi, ' ')
    .replace(/<\/o:p>/gi, '\n')
    // Strip all remaining HTML tags → space
    .replace(/<[^>]*>/g, ' ')
    // Decode common HTML entities AFTER tag stripping
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/g, "'")
    // Collapse spaces/tabs only (preserve newlines)
    .replace(/[ \t]+/g, ' ')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  // v11.3 HEURISTIC FALLBACK: if HTML stripping yielded no newlines but body is long,
  // inject newlines before common disbursement-email structure markers. This is a
  // pragmatic fix for Outlook Web's all-inline HTML format that our regex can't
  // structurally detect. Not perfect, but produces readable output for the typical
  // email shapes clients send.
  if (bodyForDisplay.length > 200 && bodyForDisplay.indexOf('\n') === -1) {
    bodyForDisplay = bodyForDisplay
      // Before common field labels: put on their own line
      .replace(/\s+(Initiator|Purpose|Payment Date|Payroll Period|Cost Center|Total Amount|Payment Type|Approvals?|Approved by|Requested by|Regards|Best regards|Sincerely|Thanks|Thank you)\s*[:,]/gi, '\n$1:')
      // Bullet items (- Name, Role)
      .replace(/\s+-\s+([A-Z])/g, '\n- $1')
      // Sentence boundaries (.  Capital letter) — keep conservative, only after 3+ word sentence
      .replace(/([a-z]{3,}\.)\s+([A-Z])/g, '$1\n$2')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }
  // Strip Outlook external-email warnings from BOTH versions
  const stripWarnings = (s) => s
    .replace(/You don't often get email from[^.]*\./g, '')
    .replace(/Learn why this is important/g, '')
    .replace(/EXTERNAL EMAIL:[^.]*\./g, '')
    .replace(/This email originated from outside of the organization[^.]*\./g, '')
    .trim();
  bodyForDisplay = stripWarnings(bodyForDisplay);
  // AI version: fully collapsed (same semantics as pre-v11.1)
  body = bodyForDisplay.replace(/\s+/g, ' ').trim();
} else {
  const raw = d.body?.body || d.bodyPreview || d.body || '';
  body = typeof raw === 'string' ? raw : '';
  var bodyForDisplay = body;
}

let from = '';
if (isEmail) {
  // Outlook format: from.emailAddress.address
  if (d.from && d.from.emailAddress && d.from.emailAddress.address) {
    from = d.from.emailAddress.address;
  } else {
    let rawFrom = getHeader('From');
    if (!rawFrom) {
      for (const [key, val] of Object.entries(d)) {
        if (key.toLowerCase().includes('from') && typeof val === 'string' && val.includes('@')) {
          rawFrom = val; break;
        }
      }
    }
    if (typeof rawFrom === 'string' && rawFrom) {
      const m = rawFrom.match(/<([^>]+)>/);
      from = m ? m[1] : rawFrom.trim();
    }
  }
} else {
  from = d.body?.from || d.from || '';
}

// Outlook: toRecipients[].emailAddress.address, ccRecipients, receivedDateTime, conversationId
const to_email = isEmail ? (d.toRecipients ? d.toRecipients.map(r => r.emailAddress ? r.emailAddress.address : '').join(', ') : getHeader('To')) : '';
const cc_emails = isEmail ? (d.ccRecipients ? d.ccRecipients.map(r => r.emailAddress ? r.emailAddress.address : '').join(', ') : getHeader('Cc')) : '';
const reply_to = isEmail ? (d.replyTo ? (Array.isArray(d.replyTo) ? d.replyTo.map(r => r.emailAddress ? r.emailAddress.address : '').join(', ') : '') : getHeader('Reply-To')) : '';
const email_date = isEmail ? (d.receivedDateTime || getHeader('Date')) : '';
const message_id = d.id || (isEmail ? getHeader('Message-ID') : '') || '';
const thread_id = d.conversationId || d.threadId || '';

let has_attachments = d.hasAttachments || false;
const attachment_names = [];
function scanParts(parts) {
  if (!Array.isArray(parts)) return;
  for (const part of parts) {
    if (part.filename && part.filename.length > 0) {
      has_attachments = true;
      attachment_names.push(part.filename);
    }
    if (part.parts) scanParts(part.parts);
  }
}
if (d.payload && d.payload.parts) scanParts(d.payload.parts);
// Outlook attachments: already handled via downloadAttachments option in trigger node

// === v3 NEW: Binary attachment extraction (n8n Cloud Task Runner compatible) ===
const attachment_base64_list = [];
const MAX_ATTACHMENTS = 2;
const MAX_SIZE = 4 * 1024 * 1024; // 4MB Groq hard limit

if (item.binary) {
  const keys = Object.keys(item.binary).filter(k => k.startsWith('attachment_'));
  for (let j = 0; j < Math.min(keys.length, MAX_ATTACHMENTS); j++) {
    const meta = item.binary[keys[j]];
    const mime = meta.mimeType || '';
    // v9: Populate attachment_names for Outlook (was Gmail-only via scanParts)
    if (meta.fileName && !attachment_names.includes(meta.fileName)) {
      attachment_names.push(meta.fileName);
      has_attachments = true;
    }
    if (mime.startsWith('image/') || mime === 'application/pdf') {
      try {
        // Task Runner: use helpers.getBinaryDataBuffer (no this.)
        const buffer = await helpers.getBinaryDataBuffer($itemIndex, keys[j]);
        if (buffer.length <= MAX_SIZE) {
          attachment_base64_list.push({
            filename: meta.fileName || keys[j],
            mimeType: mime,
            base64: buffer.toString('base64'),
            sizeBytes: buffer.length
          });
        }
      } catch (e) { /* Binary extraction failed — continue without */ }
    }
  }
}

// v10/KAN-30 #2: sync has_attachments with real count (Outlook hasAttachments flag can lie when binaries not downloaded)
has_attachments = attachment_names.length > 0;

const prompt = `You are an email parser for Wave Money's EMI (Electronic Money Issuer) salary disbursement pipeline in Myanmar.

Analyze this email and extract structured data.

EMAIL SUBJECT: ${subject}
EMAIL BODY: ${body}
FROM: ${from}

Return a JSON object with these exact fields:
{
  "is_disbursement": true or false (is this a salary/EMI/disbursement/OTC request?),
  "company": "company name requesting disbursement",
  "amount": number (total amount in MMK, 0 if not found),
  "type": "SalaryToOTC" if OTC or over-the-counter is mentioned, otherwise "SalaryToMA",
  "approvers": [{"name": "person name", "role": "their title/role", "status": "Approved"}],
  "body_preview": "first 200 characters of the email body",
  "payment_date": "the date the client wants the salary to be disbursed (their intended pay day), format YYYY-MM-DD or as written; empty string if not mentioned",
  "payroll_period": "the time period the salary covers (e.g., 'March 2026' or 'Apr 1-15, 2026'); empty string if not mentioned. NOTE: payment_date is WHEN money moves, payroll_period is WHAT WORK PERIOD the money covers — these are different",
  "initiator_name": "the person or role WITHIN THE CLIENT COMPANY who is initiating this disbursement request (e.g., 'HR Manager', 'Thida Hlaing, Payroll Specialist', 'Finance Director'). This is typically the sender or a person named at the top/bottom of the email as 'Requested by' or 'From'. DIFFERENT from approvers. Empty string if not stated explicitly — do NOT infer from email domain.",
  "purpose": "why this disbursement is being made (e.g., 'March 2026 Salary', 'Q1 2026 Bonus', 'Contractor Payments for Project X'). Empty string if not mentioned.",
  "cost_center": "accounting cost center or department code if mentioned (e.g., 'HR-OPS-001', 'FIN-2026-Q1', 'DEPT-SALES'). Empty string if not mentioned."
}

IMPORTANT: Return ONLY the JSON object, no explanation or markdown.`;

return {
  json: {
    _source: source,
    from_email: from,
    original_subject: subject,
    prompt: prompt,
    to_email: to_email,
    cc_emails: cc_emails,
    reply_to: reply_to,
    email_date: email_date,
    message_id: message_id,
    thread_id: thread_id,
    has_attachments: has_attachments,
    attachment_names: attachment_names,
    attachment_count: attachment_names.length,
    // v11.1: pass full email body to dashboard with line breaks preserved
    // (capped at 2000 chars; dashboard renders with white-space:pre-line CSS)
    email_body_full: (typeof bodyForDisplay === 'string' ? bodyForDisplay : body).substring(0, 2000),
    // v3: binary attachment data for vision processing
    attachment_base64: attachment_base64_list[0] || null,
    vision_eligible: attachment_base64_list.length > 0,
  }
};

// Employee List Extract (v8 — same as v7, unchanged)
// v7: Error guard + all fixes baked in
// MODE: Run Once for Each Item (n8n 2.x Task Runner compatible)

const item = $input.item;
if (!item.json || typeof item.json !== 'object') return { json: { ...item.json, _employee_result: null, _employee_status: 'skipped' } };
const d = item.json;

const prepData = $('Prepare for AI v3').first().json;
const attachment = prepData.attachment_base64;

if (!attachment || !prepData.vision_eligible) {
  return { json: { ...d, _employee_result: null, _employee_status: 'no_attachment' } };
}

const staticData = $getWorkflowStaticData('global');
if ((staticData.visionCalls || 0) >= 20) {
  return { json: { ...d, _employee_result: null, _employee_status: 'rate_limited' } };
}
staticData.visionCalls = (staticData.visionCalls || 0) + 1;

const isPdf = attachment.mimeType === 'application/pdf' ||
  (attachment.mimeType === 'application/octet-stream' &&
    (attachment.filename || '').toLowerCase().endsWith('.pdf'));

const prompt = 'Extract the employee/payroll list AND ticket-level metadata from this document. Return JSON only: {"employees":[{"name":"Full Name as written","account_or_phone":"phone or account number exactly as shown","amount":0}],"total_amount":0,"employee_count":0,"corporate_wallet":"","currency":"","confidence":0.0}. Rules: Extract EVERY employee row. name: the employee full name as printed (required — never empty). account_or_phone: copy exact digits (phone, MSISDN, bank account, whatever the document shows). amount: numeric only, no commas. corporate_wallet: the source funding wallet/account shown in the document header (labels like Corporate Wallet / Funding Source Account / Payment Source). currency: MMK/USD/EUR/etc. explicit only. If no employee table found, return empty employees array with confidence 0.';

try {
  let parsed = { employees: [], confidence: 0 };

  if (isPdf) {
    // === GEMINI PATH (PDF native via inlineData) ===
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=REPLACE_WITH_GEMINI_API_KEY',
      headers: { 'content-type': 'application/json' },
      body: {
        contents: [{ parts: [
          { text: prompt + '\n\nIMPORTANT: Return ONLY valid JSON, no explanation or markdown.' },
          { inlineData: { mimeType: 'application/pdf', data: attachment.base64 } }
        ]}],
        generationConfig: { temperature: 0.1, maxOutputTokens: 4000 }
      },
      json: true
    });
    if (resp.candidates && resp.candidates[0] && resp.candidates[0].content) {
      const content = resp.candidates[0].content.parts[0].text || '';
      const cleaned = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
      try { parsed = JSON.parse(cleaned); } catch(e) {
        const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
        if (jsonMatch) { try { parsed = JSON.parse(jsonMatch[0]); } catch(e2) {} }
      }
    }
  } else {
    // === GROQ PATH (images - unchanged, free, proven) ===
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.groq.com/openai/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer REPLACE_WITH_GROQ_API_KEY',
        'Content-Type': 'application/json'
      },
      body: {
        model: 'meta-llama/llama-4-scout-17b-16e-instruct',
        messages: [{
          role: 'user',
          content: [
            { type: 'text', text: prompt },
            { type: 'image_url', image_url: { url: 'data:' + attachment.mimeType + ';base64,' + attachment.base64 } }
          ]
        }],
        response_format: { type: 'json_object' },
        temperature: 0.1,
        max_tokens: 4000
      },
      json: true
    });
    if (resp.choices && resp.choices[0]) {
      const content = resp.choices[0].message.content || '';
      try { parsed = JSON.parse(content); } catch(e) {}
    }
  }

  return { json: { ...d, _employee_result: parsed, _employee_status: isPdf ? 'success_gemini_pdf' : 'success', _employee_provider: isPdf ? 'gemini' : 'groq' } };

} catch(e) {
  return { json: { ...d, _employee_result: { error_message: e.message || String(e) }, _employee_status: isPdf ? 'gemini_api_error' : 'api_error' } };
}

// Parse AI response, validate authority matrix, merge vision results (v8)
// v8: webhook POST moved inside loop — uses response's ticket_id for clean dashboard URL
// v3: vision merge, cross-validation, AMOUNT_MISMATCH scenario

const items = $input.all();
const results = [];

// Retrieve metadata from Prepare node (HTTP Request + Vision nodes replace item data)
const prepData = $('Prepare for AI v3').first().json;
const source = prepData._source;
const from_email = prepData.from_email;
const original_subject = prepData.original_subject;
const to_email = prepData.to_email || '';
const cc_emails = prepData.cc_emails || '';
const reply_to = prepData.reply_to || '';
const email_date = prepData.email_date || '';
const message_id = prepData.message_id || '';
const thread_id = prepData.thread_id || '';
const has_attachments = prepData.has_attachments || false;
const attachment_names = prepData.attachment_names || [];
const attachment_count = prepData.attachment_count || 0;

for (const item of items) {
  const d = item.json;

  // Extract AI response text — Groq/OpenAI format
  let aiText = '';
  if (d.choices && d.choices[0]) {
    aiText = d.choices[0].message.content || '';
  }

  // Parse JSON from AI response
  let parsed = {};
  try {
    parsed = JSON.parse(aiText);
  } catch (e) {
    // Fallback: try extracting from markdown code block
    const jsonMatch = aiText.match(/```json?\s*([\s\S]*?)```/);
    if (jsonMatch) {
      try { parsed = JSON.parse(jsonMatch[1]); } catch (e2) {}
    }
  }

  // AI-powered keyword filter: skip non-disbursement emails
  if (!parsed.is_disbursement) {
    return [];
  }

  // AUTHORITY MATRIX CHECK
  const required = ['Sales HOD', 'Finance Manager'];
  const matrixResults = required.map(req => {
    const found = (parsed.approvers || []).find(a =>
      a.role.toLowerCase().includes(req.toLowerCase())
    );
    return {
      requiredRole: req,
      found: !!found,
      foundName: found ? found.name : 'MISSING',
    };
  });
  const matrixComplete = matrixResults.every(m => m.found);

  // SCENARIO DETECTION
  let scenario = 'NORMAL';
  if (!matrixComplete) {
    scenario = 'MISSING_APPROVAL';
  }

  // BUILD TICKET PAYLOAD (includes metadata)
  const ticket = {
    company: parsed.company || 'Unknown Company',
    type: parsed.type || 'SalaryToMA',
    amount_requested: parsed.amount || 0,
    amount_on_bank_slip: parsed.amount || 0,
    currency: 'MMK',
    approvals: parsed.approvers || [],
    required_approvals: required,
    body_preview: parsed.body_preview || '',
    email_body_full: prepData.email_body_full || '',  // v5.1: full email body for dashboard
    // v11/KAN-36: initiator + purpose + cost_center from email extraction
    initiator_name: parsed.initiator_name || '',
    purpose: parsed.purpose || '',
    cost_center: parsed.cost_center || '',
    original_subject: original_subject,
    parsed_at: new Date().toISOString(),
    scenario,
    approval_matrix_complete: matrixComplete,
    ai_parsed: true,
    from_email: from_email,
    to_email: to_email,
    cc_emails: cc_emails,
    reply_to: reply_to,
    email_date: email_date,
    message_id: message_id,
    thread_id: thread_id,
    has_attachments: has_attachments,
    attachment_names: attachment_names,
    attachment_count: attachment_count,
  };

  // === v3: Vision merge ===
  const visionResult = d._vision_result || null;
  const visionStatus = d._vision_status || 'none';

  if (visionResult && (visionResult.confidence > 0 || visionResult.doc_type || visionResult.total_amount)) {
    // Cross-validate amount (the "wow" moment for Tuesday demo)
    if (visionResult.total_amount > 0 && ticket.amount_requested > 0) {
      const diff = Math.abs(visionResult.total_amount - ticket.amount_requested);
      ticket.amount_mismatch = diff > (ticket.amount_requested * 0.01); // 1% tolerance
      ticket.amount_on_document = visionResult.total_amount;
      // Update bank slip amount for dashboard compatibility
      if (visionResult.total_amount > 0) {
        ticket.amount_on_bank_slip = visionResult.total_amount;
      }
    }
    ticket.document_type = visionResult.doc_type;
    ticket.document_signers = visionResult.authorized_signers;
    ticket.depositor_name = visionResult.depositor_name || '';
    ticket.remark = visionResult.remark || '';
    ticket.transaction_id = visionResult.transaction_id || visionResult.reference_number || '';
    // v11/KAN-36: document-side values for side-by-side comparison with email extraction
    ticket.doc_company_name = visionResult.company_name || visionResult.depositor_name || '';
    ticket.doc_payment_date = visionResult.payment_date || '';
    ticket.doc_initiator_name = visionResult.initiator_name || '';
    ticket.doc_purpose = visionResult.purpose || '';
    ticket.doc_cost_center = visionResult.cost_center || '';
    // v11.4/KAN-36 Source Info: ticket-level corporate wallet + currency
    // from attachment header (preferred source). Fallback chain below.
    ticket.corporate_wallet = visionResult.corporate_wallet || '';
    // Vision currency takes precedence over default — only overwrite if extracted.
    if (visionResult.currency) ticket.currency = visionResult.currency;
    ticket.vision_parsed = true;
    ticket.vision_confidence = visionResult.confidence;
    // Override: if valid data extracted but confidence is 0, set reasonable default
    if (ticket.vision_confidence === 0 && (visionResult.doc_type || visionResult.total_amount > 0)) {
      ticket.vision_confidence = 0.85;
    }
  }

  // Override scenario if vision found amount mismatch
  if (ticket.amount_mismatch) scenario = 'AMOUNT_MISMATCH';
  ticket.scenario = scenario; // Update after potential override

  // Vision metadata for output
  ticket.vision_status = visionStatus;


  // === v4: Employee list merge ===
  const employeeResult = d._employee_result || null;
  const employeeStatus = d._employee_status || 'none';

  if (employeeResult && employeeResult.employees && employeeResult.employees.length > 0) {
    ticket.extracted_employees = employeeResult.employees;
    ticket.extracted_employee_count = employeeResult.employee_count || employeeResult.employees.length;
    ticket.employee_extraction_confidence = employeeResult.confidence || 0;
    ticket.employee_extraction_status = 'success';
    // v11.4: Source Info fallback — Employee Extract may have caught corporate_wallet
    // or currency from its view of the attachment header even if the separate Vision
    // Process call didn't. Prefer Vision results but backfill from here.
    if (!ticket.corporate_wallet && employeeResult.corporate_wallet) ticket.corporate_wallet = employeeResult.corporate_wallet;
    if (ticket.currency === 'MMK' && employeeResult.currency) ticket.currency = employeeResult.currency;

    // Cross-validation: sum of employee amounts vs email amount
    const empTotal = employeeResult.employees.reduce((s, e) => s + (e.amount || 0), 0);
    ticket.employee_total_extracted = empTotal;
    if (ticket.amount_requested > 0 && empTotal > 0) {
      const diff = Math.abs(empTotal - ticket.amount_requested);
      ticket.employee_amount_mismatch = diff > (ticket.amount_requested * 0.01);
    }
  } else {
    ticket.extracted_employees = [];
    ticket.extracted_employee_count = 0;
    ticket.employee_extraction_confidence = 0;
    ticket.employee_extraction_status = employeeStatus;
    ticket.employee_total_extracted = 0;
    ticket.employee_amount_mismatch = false;
  }

  // v8: POST to webhook FIRST, get real ticket_number back, then build clean URL
  const webhookPayload = {
    ...ticket,
    attachment_base64: prepData.attachment_base64 ? prepData.attachment_base64.base64 : null,
    attachment_mime_type: prepData.attachment_base64 ? prepData.attachment_base64.mimeType : null,
    attachment_filename: prepData.attachment_base64 ? prepData.attachment_base64.filename : null,
  };
  let ticketId = null;
  let dashboardUrl = 'https://project-ii0tm.vercel.app';
  try {
    const webhookResp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://project-ii0tm.vercel.app/api/webhook',
      headers: {
        'Content-Type': 'application/json',
        'X-Webhook-Secret': 'REPLACE_WITH_WEBHOOK_SECRET'
      },
      body: webhookPayload,
      json: true
    });
    if (webhookResp && webhookResp.ticket_id) {
      ticketId = webhookResp.ticket_id;
      dashboardUrl = webhookResp.dashboard_url || `https://project-ii0tm.vercel.app/?ticket=${ticketId}`;
    }
  } catch(e) { /* fallback — notification still sends with homepage URL */ }

  results.push({
    json: {
      _source: source,
      ticket_id: ticketId,
      dashboard_url: dashboardUrl,
      company: parsed.company || 'Unknown Company',
      amount: parsed.amount || 0,
      type: parsed.type || 'SalaryToMA',
      scenario,
      matrix_complete: matrixComplete,
      matrix_details: matrixResults,
      from_email: from_email,
      original_subject: original_subject,
      to_email: to_email,
      cc_emails: cc_emails,
      email_date: email_date,
      has_attachments: has_attachments,
      attachment_count: attachment_count,
      // v3: vision output
      vision_parsed: ticket.vision_parsed || false,
      vision_confidence: ticket.vision_confidence || 0,
      vision_status: visionStatus,
      amount_on_document: ticket.amount_on_document || 0,
      document_type: ticket.document_type || '',
      document_signers: ticket.document_signers || [],
      // v4: Employee extraction fields
      extracted_employees: ticket.extracted_employees || [],
      extracted_employee_count: ticket.extracted_employee_count || 0,
      employee_extraction_confidence: ticket.employee_extraction_confidence || 0,
      employee_extraction_status: ticket.employee_extraction_status || 'none',
      employee_total_extracted: ticket.employee_total_extracted || 0,
      employee_amount_mismatch: ticket.employee_amount_mismatch || false,
      // v4: Finance fields
      depositor_name: ticket.depositor_name || '',
      remark: ticket.remark || '',
      email_body_full: ticket.email_body_full || '',
      transaction_id: ticket.transaction_id || '',
      // v10/KAN-30 #1+#3: payment type classification + 7-item verification checklist
      payment_type: ticket.extracted_employee_count > 0 ? 'salarytoMA' : 'salarytoOTC',
      // v10.1/KAN-35 + verbal: separate Payment Date + Payroll Period fields
      payment_date: parsed.payment_date || '',
      payroll_period: parsed.payroll_period || '',
      // v11/KAN-36: new extraction fields (email side)
      initiator_name: parsed.initiator_name || '',
      purpose: parsed.purpose || '',
      cost_center: parsed.cost_center || '',
      // v11/KAN-36: document-side values for side-by-side comparison
      doc_company_name: ticket.doc_company_name || '',
      doc_payment_date: ticket.doc_payment_date || '',
      doc_initiator_name: ticket.doc_initiator_name || '',
      doc_purpose: ticket.doc_purpose || '',
      doc_cost_center: ticket.doc_cost_center || '',
      // v11.4/KAN-36 Source Info: ticket-level fields for header row display
      corporate_wallet: ticket.corporate_wallet || '',
      currency: ticket.currency || 'MMK',
      verification: {
        company_name: !!(parsed.company && parsed.company !== 'Unknown Company'),
        payment_type: true,
        amount: (parsed.amount || 0) > 0,
        payment_date: !!parsed.payment_date,
        payroll_period: !!parsed.payroll_period,
        approval: matrixComplete,
        attachment: (attachment_count || 0) > 0,
        employee_list: (ticket.extracted_employee_count || 0) > 0,
        // v11/KAN-36: new verification booleans
        initiator_name: !!parsed.initiator_name,
        purpose: !!parsed.purpose,
        cost_center: !!parsed.cost_center
      },
      // v6: Pass attachment to webhook for Supabase Storage
      attachment_base64: prepData.attachment_base64 ? prepData.attachment_base64.base64 : null,
      attachment_mime_type: prepData.attachment_base64 ? prepData.attachment_base64.mimeType : null,
      attachment_filename: prepData.attachment_base64 ? prepData.attachment_base64.filename : null,
    }
  });
}

// v8: Webhook POST moved inside loop — ticket_id now available in results

return results;

