// Vision Process (v8 — same as v7, unchanged)
// v7: Error guard + all fixes baked in
// Model: gemini-2.5-flash (stable). To upgrade: replace with gemini-3-flash-preview
// Gemini handles PDF natively via inlineData (no conversion needed)
// Groq path unchanged for images (free, proven)
// MODE: Run Once for Each Item (n8n 2.x Task Runner compatible)

const item = $input.item;
if (!item.json || typeof item.json !== 'object') return { json: { _vision_result: null, _vision_status: 'skipped' } };
const d = item.json;

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (staticData.date !== today) {
  staticData.date = today;
  staticData.textCalls = 0;
  staticData.visionCalls = 0;
  staticData.visionErrors = 0;
}

const prepData = $('Prepare for AI v3').first().json;
const attachment = prepData.attachment_base64;
const visionEligible = prepData.vision_eligible;

let visionResult = null;
let visionStatus = 'none';
let visionUsage = null;

const rateLimitOK = staticData.visionCalls < 20;
const circuitBreakerOK = (staticData.visionErrors || 0) < 5;

const isPdf = attachment && (
  attachment.mimeType === 'application/pdf' ||
  (attachment.mimeType === 'application/octet-stream' &&
    (attachment.filename || '').toLowerCase().endsWith('.pdf'))
);

const visionPrompt = 'Extract from this bank slip / payment document / payroll form. Return JSON only:\n{\n  "doc_type": "bank_slip" | "payment_instruction" | "payroll_form" | "unknown",\n  "depositor_name": "",\n  "company_name": "",\n  "total_amount": 0,\n  "currency": "",\n  "remark": "",\n  "payment_date": "",\n  "payment_method": "",\n  "transaction_id": "",\n  "authorized_signers": [{"name": "", "role": ""}],\n  "reference_number": "",\n  "initiator_name": "",\n  "purpose": "",\n  "cost_center": "",\n  "corporate_wallet": "",\n  "confidence": 0.0\n}\nField rules:\n- corporate_wallet: the SOURCE/FUNDING wallet ID or account number used to PAY FROM. Look for labels like "Corporate Wallet", "Funding Source Account", "Source Account", "Payment Source". Include the identifier shown (e.g. "1200000289" or "CHASE OPERATING - 123456789"). Empty string if not visible.\n- currency: the currency code explicitly stated (MMK, USD, EUR, etc.). Default to empty string — do NOT infer from amount format.\n- initiator_name, purpose, cost_center: return exactly what the document shows. Empty string if not present. Do NOT infer.';

if (visionEligible && attachment && rateLimitOK && circuitBreakerOK) {
  try {
    staticData.visionCalls++;
    let resp;

    if (isPdf) {
      // === GEMINI PATH (PDF native support via inlineData) ===
      resp = await helpers.httpRequest({
        method: 'POST',
        url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=REPLACE_WITH_GEMINI_API_KEY',
        headers: { 'content-type': 'application/json' },
        body: {
          contents: [{ parts: [
            { text: visionPrompt + '\n\nIMPORTANT: Return ONLY valid JSON, no explanation or markdown.' },
            { inlineData: { mimeType: 'application/pdf', data: attachment.base64 } }
          ]}],
          generationConfig: { temperature: 0.1, maxOutputTokens: 1000 }
        },
        json: true
      });
      if (resp.candidates && resp.candidates[0] && resp.candidates[0].content) {
        const content = resp.candidates[0].content.parts[0].text || '';
        const cleaned = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
        try {
          visionResult = JSON.parse(cleaned);
          visionStatus = 'success_gemini_pdf';
          staticData.visionErrors = 0;
        } catch (e) {
          const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
          if (jsonMatch) {
            try { visionResult = JSON.parse(jsonMatch[0]); visionStatus = 'success_gemini_pdf'; } catch(e2) { visionStatus = 'parse_error'; staticData.visionErrors++; }
          } else { visionStatus = 'parse_error'; staticData.visionErrors++; }
        }
      }
      visionUsage = resp.usageMetadata || null;

    } else {
      // === GROQ PATH (images - unchanged, free, proven) ===
      resp = await helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: {
          'Authorization': 'Bearer REPLACE_WITH_GROQ_API_KEY',
          'Content-Type': 'application/json'
        },
        body: {
          model: 'meta-llama/llama-4-scout-17b-16e-instruct',
          messages: [{
            role: 'user',
            content: [
              { type: 'text', text: visionPrompt },
              { type: 'image_url', image_url: { url: 'data:' + attachment.mimeType + ';base64,' + attachment.base64 } }
            ]
          }],
          response_format: { type: 'json_object' },
          temperature: 0.1,
          max_tokens: 500
        },
        json: true
      });
      if (resp.choices && resp.choices[0]) {
        const content = resp.choices[0].message.content || '';
        try {
          visionResult = JSON.parse(content);
          visionStatus = 'success';
          staticData.visionErrors = 0;
        } catch (e) {
          visionStatus = 'parse_error';
          staticData.visionErrors++;
        }
      }
      visionUsage = resp.usage || null;
    }

  } catch (e) {
    visionStatus = isPdf ? 'gemini_api_error' : 'api_error';
    visionResult = { error_message: e.message || String(e) };
    staticData.visionErrors++;
  }
} else if (visionEligible && !rateLimitOK) {
  visionStatus = 'rate_limited';
} else if (visionEligible && !circuitBreakerOK) {
  visionStatus = 'circuit_breaker';
}

return {
  json: {
    ...d,
    _vision_result: visionResult,
    _vision_status: visionStatus,
    _vision_usage: visionUsage,
    _vision_provider: isPdf ? 'gemini' : 'groq',
  }
};
